// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package detectiveimport ("context""fmt""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/detective""github.com/hashicorp/aws-sdk-go-base/v2/awsv1shim/v2/tfawserr""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry")func FindGraphByARN(ctx context.Context, conn *detective.Detective, arn string) (*detective.Graph, error) {input := &detective.ListGraphsInput{}var result *detective.Grapherr := conn.ListGraphsPagesWithContext(ctx, input, func(page *detective.ListGraphsOutput, lastPage bool) bool {if page == nil {return !lastPage}for _, graph := range page.GraphList {if graph == nil {continue}if aws.StringValue(graph.Arn) == arn {result = graphreturn false}}return !lastPage})if tfawserr.ErrCodeEquals(err, detective.ErrCodeResourceNotFoundException) {return nil, &retry.NotFoundError{LastError:err,LastRequest: input,}}if err != nil {return nil, err}if result == nil {return nil, &retry.NotFoundError{Message:fmt.Sprintf("No detective graph with arn %q", arn),LastRequest: input,}}return result, nil}func FindInvitationByGraphARN(ctx context.Context, conn *detective.Detective, graphARN string) (*string, error) {input := &detective.ListInvitationsInput{}var result *stringerr := conn.ListInvitationsPagesWithContext(ctx, input, func(page *detective.ListInvitationsOutput, lastPage bool) bool {for _, invitation := range page.Invitations {if aws.StringValue(invitation.GraphArn) == graphARN {result = invitation.GraphArnreturn false}}return !lastPage})if tfawserr.ErrCodeEquals(err, detective.ErrCodeResourceNotFoundException) {return nil, &retry.NotFoundError{LastError:err,LastRequest: input,}}if err != nil {return nil, err}if result == nil {return nil, &retry.NotFoundError{Message:fmt.Sprintf("No member found with arn %q ", graphARN),LastRequest: input,}}return result, nil}func FindMemberByGraphARNAndAccountID(ctx context.Context, conn *detective.Detective, graphARN string, accountID string) (*detective.MemberDetail, error) {input := &detective.ListMembersInput{GraphArn: aws.String(graphARN),}var result *detective.MemberDetailerr := conn.ListMembersPagesWithContext(ctx, input, func(page *detective.ListMembersOutput, lastPage bool) bool {if page == nil {return !lastPage}for _, member := range page.MemberDetails {if member == nil {continue}if aws.StringValue(member.AccountId) == accountID {result = memberreturn false}}return !lastPage})if tfawserr.ErrCodeEquals(err, detective.ErrCodeResourceNotFoundException) {return nil, &retry.NotFoundError{LastError:err,LastRequest: input,}}if err != nil {return nil, err}if result == nil {return nil, &retry.NotFoundError{Message:fmt.Sprintf("No member found with arn %q and accountID %q", graphARN, accountID),LastRequest: input,}}return result, nil}